          <div className="rp-bar-row" key={d.id}>
            <span className="rp-bar-label">{d.name}</span>
            <div className="rp-bar-track"><div className="rp-bar-fill" style={{ width: `${(v/5)*100}%`, background: d.color, opacity: v ? 0.8 : 0.1 }} /></div>
            <span className="rp-bar-val" style={{ color: v ? d.color : 'var(--text-muted)' }}>{v||'\u2014'}</span>
          </div>
        );
      })}

      {/* Growth areas */}
      {totalRated > 0 && (
        <>
          <div className="rp-section-title">Top Growth Areas</div>
          {growthAreas.map(g => (
            <div className="rp-growth-item" key={g.name}>
              <div className="rp-growth-name">{g.name}</div>
              <div className="rp-growth-score">{g.sec} \u00B7 {g.score}/5</div>
            </div>
          ))}
        </>
      )}

      {/* Archetype guidance */}
      {guide && arcObj && (
        <>
          <div className="rp-section-title" style={{ color: arcObj.color }}>Guidance for {arcObj.name}</div>
          <div className="guidance-card"><div className="guidance-label">Strength to show</div><div className="guidance-text">{guide.strength}</div></div>
          <div className="guidance-card"><div className="guidance-label">Watch for</div><div className="guidance-text">{guide.watch_for}</div></div>
          <div className="guidance-card"><div className="guidance-label">Case study emphasis</div><div className="guidance-text">{guide.emphasis}</div></div>
        </>
      )}

      <div className="rp-btn-row">
        <button className="btn btn-ghost" onClick={onReset}>Reset</button>
        <button className="btn btn-fill" onClick={() => window.print()}>Print</button>
      </div>
      <div className="footer">
        <div className="footer-logo">Jacksonville Design Community</div>
        <div className="footer-sub">Portfolio Assessment \u00B7 {new Date().getFullYear()}</div>
      </div>
    </div>
  );
}

