    first_impression: 0–5,
    navigation: 0–5,
    about_story: 0–5,
    visual_quality: 0–5,
    responsiveness: 0–5,
    writing_quality: 0–5,
    contact_cta: 0–5,
    loading_perf: 0–5,
  },

  // Section 2: Case Studies (dynamic array)
  caseStudies: [
    {
      id: "cs_1",
      name: "Project Name",
      scores: {
        problem_framing: 0–5,
        process_depth: 0–5,
        storytelling: 0–5,
        outcomes: 0–5,
        visual_execution: 0–5,
        role_clarity: 0–5,
      },
    },
    // ... up to 6
  ],

  // Section 3: Portfolio Strategy
