with open('/mnt/user-data/outputs/portfolio-scorecard-requirements.md', 'r') as f:
    content = f.read()

import re
chars = {}
for m in re.finditer(r'[^\x00-\x7F]', content):
    c = m.group()
    code = hex(ord(c))
    if code not in chars:
        chars[code] = {'char': c, 'count': 0, 'name': ''}
    chars[code]['count'] += 1

import unicodedata
for code, info in sorted(chars.items()):
    try:
        name = unicodedata.name(info['char'])
    except:
        name = 'UNKNOWN'
    print(f'{code} ({info[\"count\"]:3d}x) = \"{info[\"char\"]}\"  {name}')
